/**
 * @param {string[]} chunks
 * @param {string[]} queries
 * @return {number[]}
 */
function solve(chunks, queries) {
    const s = chunks.join('');
    const results = new Array(queries.length).fill(0);

    /**
     * Checks if a character is valid for a word structure (lowercase letter or hyphen).
     * @param {string} char
     * @returns {boolean}
     */
    const isWordChar = (char) => {
        return (char >= 'a' && char <= 'z') || char === '-';
    };

    /**
     * Extracts all valid words from the string s.
     * A word is a maximal contiguous sequence of word characters (letters or hyphens)
     * that is not a substring of a strictly longer word composed of the same characters.
     * The problem definition implies that any sequence of word characters separated by
     * non-word characters forms a potential candidate. The "not part of a longer word"
     * constraint is inherently handled by finding maximal contiguous blocks of word characters.
     *
     * @param {string} text
     * @returns {Set<string>} A set of all unique valid words.
     */
    const extractWords = (text) => {
        const words = new Set();
        let currentWord = "";
        for (let i = 0; i < text.length; i++) {
            const char = text[i];
            if (isWordChar(char)) {
                currentWord += char;
            } else {
                if (currentWord.length > 0) {
                    // Check for the specific word structure requirements related to hyphens.
                    // The problem states: "can contain hyphens ('-'), but only if each hyphen
                    // is surrounded by lowercase letters."

                    let isValid = true;
                    // Check the extracted word for illegal hyphen placements
                    for (let j = 0; j < currentWord.length; j++) {
                        if (currentWord[j] === '-') {
                            const prev = j > 0 ? currentWord[j - 1] : null;
                            const next = j < currentWord.length - 1 ? currentWord[j + 1] : null;
                            if (prev === null || next === null || !(prev >= 'a' && prev <= 'z') || !(next >= 'a' && next <= 'z')) {
                                isValid = false;
                                break;
                            }
                        }
                    }

                    // If the structure is valid, add the maximal contiguous segment.
                    // The "not part of a longer word" constraint is satisfied by processing maximal segments.
                    if (isValid) {
                        words.add(currentWord);
                    }
                    currentWord = "";
                }
            }
        }
        // Process the last segment if it exists
        if (currentWord.length > 0) {
            let isValid = true;
            for (let j = 0; j < currentWord.length; j++) {
                if (currentWord[j] === '-') {
                    const prev = j > 0 ? currentWord[j - 1] : null;
                    const next = j < currentWord.length - 1 ? currentWord[j + 1] : null;
                    if (prev === null || next === null || !(prev >= 'a' && prev <= 'z') || !(next >= 'a' && next <= 'z')) {
                        isValid = false;
                        break;
                    }
                }
            }
            if (isValid) {
                words.add(currentWord);
            }
        }
        return words;
    };

    // Since the definition of a "word" depends on the maximal contiguous sequence
    // of characters that *can* form a word (letters/hyphens), we must parse the string
    // to find all maximal segments, validate them, and then count occurrences.

    // The definition "it is not some similarly satisfying condition longer substring"
    // means we only count the maximal blocks.

    // A map to store the frequency of each valid word found.
    const wordFrequencies = new Map();

    // Iterate through the string to find all maximal valid words and count them.
    let i = 0;
    while (i < s.length) {
        if (!isWordChar(s[i])) {
            i++;
            continue;
        }

        // Start of a potential word segment
        let j = i;
        while (j < s.length && isWordChar(s[j])) {
            j++;
        }
        const segment = s.substring(i, j);

        // Validate the segment based on hyphen rules
        let isValid = true;
        for (let k = 0; k < segment.length; k++) {
            if (segment[k] === '-') {
                const prev = k > 0 ? segment[k - 1] : null;
                const next = k < segment.length - 1 ? segment[k + 1] : null;
                if (prev === null || next === null || !(prev >= 'a' && prev <= 'z') || !(next >= 'a' && next <= 'z')) {
                    isValid = false;
                    break;
                }
            }
        }

        if (isValid) {
            // The segment itself is a maximal contiguous block of word characters.
            // According to the problem, this maximal block IS a word.
            const word = segment;
            wordFrequencies.set(word, (wordFrequencies.get(word) || 0) + 1);
        }

        // Move to the next position after the segment
        i = j;
    }


    // Now, calculate the answers for the queries
    for (let q = 0; q < queries.length; q++) {
        const queryWord = queries[q];
        // Since the problem guarantees queries[i] is an effective word, it must be one
        // of the maximal segments we counted.
        results[q] = wordFrequencies.get(queryWord) || 0;
    }

    return results;
}

