use std::collections::HashMap;

fn solve(chunks: Vec<String>, queries: Vec<String>) -> Vec<i64> {
    let s: String = chunks.join("");
    let mut word_frequencies: HashMap<String, i64> = HashMap::new();

    // Helper function to check if a character is a word character (lowercase letter or hyphen)
    let is_word_char = |c: char| -> bool {
        (c >= 'a' && c <= 'z') || c == '-'
    };

    // Iterate through the string to find all maximal valid words and count them.
    let mut i = 0;
    while i < s.len() {
        let current_char = s.chars().nth(i).unwrap();

        if !is_word_char(current_char) {
            i += 1;
            continue;
        }

        // Start of a potential word segment
        let start = i;
        let mut j = i;
        while j < s.len() {
            let char_at_j = s.chars().nth(j).unwrap();
            if is_word_char(char_at_j) {
                j += 1;
            } else {
                break;
            }
        }
        let segment = &s[start..j];

        // Validate the segment based on hyphen rules
        let mut is_valid = true;
        for (k, c) in segment.chars().enumerate() {
            if c == '-' {
                // Check left neighbor
                let prev_is_letter = k > 0 && segment.chars().nth(k - 1).unwrap().is_ascii_lowercase();
                // Check right neighbor
                let next_is_letter = k < segment.len() - 1 && segment.chars().nth(k + 1).unwrap().is_ascii_lowercase();

                if !prev_is_letter || !next_is_letter {
                    is_valid = false;
                    break;
                }
            }
        }

        if is_valid {
            // The segment itself is a maximal contiguous block of word characters, and it is valid.
            let word = segment.to_string();
            *word_frequencies.entry(word).or_insert(0) += 1;
        }

        // Move to the next position after the segment
        i = j;
    }


    // Calculate the answers for the queries
    let mut results = Vec::new();
    for query_word in queries {
        let count = *word_frequencies.get(&query_word).unwrap_or(&0);
        results.push(count);
    }

    results
}
